app = Flask(__name__)

class DiskCache:
    def __init__(self, cache_dir='cache', default_ttl=3600):
        self.cache_dir = cache_dir
        self.default_ttl = default_ttl
        if not os.path.exists(cache_dir):
            os.makedirs(cache_dir)
    
    def _get_cache_key(self, key):
        hash_key = hashlib.md5(str(key).encode()).hexdigest()
        return os.path.join(self.cache_dir, f"{hash_key}.pkl")
    
    def get(self, key):
        cache_file = self._get_cache_key(key)
        
        if not os.path.exists(cache_file):
            return None
        
        try:
            with open(cache_file, 'rb') as f:
                cached_data = pickle.load(f)
            
            if time.time() > cached_data['expires_at']:
                os.remove(cache_file)
                return None
            
            return cached_data['data']
        except (pickle.PickleError, KeyError, OSError):
            return None
    
    def set(self, key, value, ttl=None):
        cache_file = self._get_cache_key(key)
        ttl = ttl if ttl is not None else self.default_ttl
        
        cached_data = {
            'data': value,
            'created_at': time.time(),
            'expires_at': time.time() + ttl
        }
        
        try:
            with open(cache_file, 'wb') as f:
                pickle.dump(cached_data, f, protocol=pickle.HIGHEST_PROTOCOL)
            return True
        except (pickle.PickleError, OSError):
            return False
    
    def delete(self, key):
        cache_file = self._get_cache_key(key)
        
        if os.path.exists(cache_file):
            try:
                os.remove(cache_file)
                return True
            except OSError:
                return False
        return False
    
    def clear(self):
        try:
            for filename in os.listdir(self.cache_dir):
                file_path = os.path.join(self.cache_dir, filename)
                if os.path.isfile(file_path) and filename.endswith('.pkl'):
                    os.remove(file_path)
            return True
        except OSError:
            return False
    
    def cleanup_expired(self):
        count = 0
        try:
            for filename in os.listdir(self.cache_dir):
                file_path = os.path.join(self.cache_dir, filename)
                if os.path.isfile(file_path) and filename.endswith('.pkl'):
                    try:
                        with open(file_path, 'rb') as f:
                            cached_data = pickle.load(f)
                        
                        if time.time() > cached_data['expires_at']:
                            os.remove(file_path)
                            count += 1
                    except (pickle.PickleError, KeyError, OSError):
                        continue
            return count
        except OSError:
            return count


cache = DiskCache(cache_dir='api_cache', default_ttl=300)


def cached_response(ttl=None, key_prefix=''):
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            cache_key_parts = [key_prefix, f.__name__]
            
            cache_key_parts.extend([str(arg) for arg in args])
            cache_key_parts.extend([f"{k}={v}" for k, v in sorted(kwargs.items())])
            
            if hasattr(request, 'args'):
                cache_key_parts.extend([f"{k}={v}" for k, v in sorted(request.args.items())])
            
            cache_key = ':'.join(cache_key_parts)
            
            cached_value = cache.get(cache_key)
            if cached_value is not None:
                return jsonify(cached_value)
            
            result = f(*args, **kwargs)
            
            if hasattr(result, 'get_json'):
                data = result.get_json()
            elif isinstance(result, tuple):
                data = result[0].get_json() if hasattr(result[0], 'get_json') else result[0]
            else:
                data = result
            
            cache.set(cache_key, data, ttl=ttl)
            
            return jsonify(data)
        
        return decorated_function
    return decorator


